import "server-only";

import { randomUUID } from "crypto";
import type {
  AgentDecision,
  PlanStep,
  PlannerAlternative,
  PlannerCritique,
  PlannerMeta,
} from "@/features/agent-runtime/types/agent";
import { MAX_PLAN_STEPS, MAX_STEP_ATTEMPTS } from "@/features/agent-runtime/core/config";

export type PlanHierarchy = {
  goals: Array<{
    id: string;
    title: string;
    successCriteria?: string | null;
    priority?: number | null;
    dependsOn?: number[] | string[] | null;
    subgoals: Array<{
      id: string;
      title: string;
      successCriteria?: string | null;
      priority?: number | null;
      dependsOn?: number[] | string[] | null;
      steps: Array<{
        title: string;
        tool?: "playwright" | "none";
        expectedObservation?: string | null;
        successCriteria?: string | null;
        phase?: string | null;
        priority?: number | null;
        dependsOn?: number[] | string[] | null;
      }>;
    }>;
  }>;
};

export function parsePlanJson(content: string): unknown {
  if (!content) return null;
  const fencedMatch = content.match(/```json\s*([\s\S]*?)```/i);
  const raw = fencedMatch ? fencedMatch[1] : content;
  if (!raw) return null;
  const match = raw.match(/\{[\s\S]*\}$/);
  const jsonText = match ? match[0] : raw;
  if (!jsonText) return null;
  try {
    const parsed: unknown = JSON.parse(jsonText);
    return parsed;
  } catch {
    return null;
  }
}

export function normalizePlannerMeta(parsed: {
  critique?: PlannerCritique;
  selfCritique?: PlannerCritique;
  alternatives?: PlannerAlternative[];
  safetyChecks?: string[];
  questions?: string[];
  taskType?: string;
  summary?: string;
  constraints?: string[];
  successSignals?: string[];
}) {
  const critique = normalizeCritique(parsed.critique ?? parsed.selfCritique);
  const safetyChecks = normalizeStringList(parsed.safetyChecks);
  const questions = normalizeStringList(parsed.questions);
  const normalizedSafetyChecks = uniqStrings([
    ...(critique?.safetyChecks ?? []),
    ...(safetyChecks ?? []),
  ]);
  const normalizedQuestions = uniqStrings([
    ...(critique?.questions ?? []),
    ...(questions ?? []),
  ]);
  const alternatives = normalizeAlternatives(parsed.alternatives);
  const taskType = normalizeTaskType(parsed.taskType);
  const summary =
    typeof parsed.summary === "string" ? parsed.summary.trim() : null;
  const constraints = normalizeStringList(parsed.constraints);
  const successSignals = normalizeStringList(parsed.successSignals);
  return {
    ...(critique && { critique }),
    ...(alternatives && { alternatives }),
    ...(normalizedSafetyChecks.length > 0 && {
      safetyChecks: normalizedSafetyChecks,
    }),
    ...(normalizedQuestions.length > 0 && { questions: normalizedQuestions }),
    ...(taskType && { taskType }),
    ...(summary && { summary }),
    ...(constraints.length > 0 && { constraints }),
    ...(successSignals.length > 0 && { successSignals }),
  } satisfies PlannerMeta;
}

export function normalizeCritique(value?: PlannerCritique | null) {
  if (!value) return null;
  const assumptions = normalizeStringList(value.assumptions);
  const risks = normalizeStringList(value.risks);
  const unknowns = normalizeStringList(value.unknowns);
  const safetyChecks = normalizeStringList(value.safetyChecks);
  const questions = normalizeStringList(value.questions);
  const hasAny =
    assumptions.length ||
    risks.length ||
    unknowns.length ||
    safetyChecks.length ||
    questions.length;
  if (!hasAny) return null;
  return {
    ...(assumptions.length > 0 && { assumptions }),
    ...(risks.length > 0 && { risks }),
    ...(unknowns.length > 0 && { unknowns }),
    ...(safetyChecks.length > 0 && { safetyChecks }),
    ...(questions.length > 0 && { questions }),
  } satisfies PlannerCritique;
}

export function normalizeStringList(value: unknown) {
  if (!Array.isArray(value)) return [];
  return value
    .filter((item) => typeof item === "string")
    .map((item) => item.trim())
    .filter(Boolean);
}

function uniqStrings(values: string[]) {
  const result: string[] = [];
  for (const value of values) {
    if (!result.includes(value)) {
      result.push(value);
    }
  }
  return result;
}

export function normalizeAlternatives(value: unknown) {
  if (!Array.isArray(value)) return null;
  const alternatives = value
    .map((entry) => {
      if (!entry || typeof entry !== "object") return null;
      const typed = entry as PlannerAlternative;
      const title = typeof typed.title === "string" ? typed.title.trim() : "";
      const steps = Array.isArray(typed.steps) ? typed.steps : [];
      if (!title || steps.length === 0) return null;
      return {
        title,
        rationale:
          typeof typed.rationale === "string" ? typed.rationale.trim() : null,
        steps,
      } satisfies PlannerAlternative;
    })
    .filter(Boolean) as PlannerAlternative[];
  return alternatives.length ? alternatives : null;
}

export function normalizeTaskType(value: unknown) {
  if (value === "web_task" || value === "extract_info") return value;
  return undefined;
}

export function buildSafetyCheckSteps(
  meta?: PlannerMeta,
  maxStepAttempts = MAX_STEP_ATTEMPTS
): PlanStep[] {
  const checks = [
    ...(meta?.safetyChecks ?? []),
    ...(meta?.critique?.safetyChecks ?? []),
  ]
    .map((check) => check.trim())
    .filter(Boolean);
  if (checks.length === 0) return [];
  const limited = checks.slice(0, 3);
  return limited.map((check) => ({
    id: randomUUID(),
    title: `Safety check: ${check}`,
    status: "pending" as const,
    tool: "none" as const,
    expectedObservation: null,
    successCriteria: null,
    phase: "observe" as const,
    priority: null,
    dependsOn: null,
    attempts: 0,
    maxAttempts: maxStepAttempts,
  }));
}

export function buildVerificationSteps(
  meta?: PlannerMeta,
  maxStepAttempts = MAX_STEP_ATTEMPTS
): PlanStep[] {
  const signals = meta?.successSignals ?? [];
  if (signals.length === 0) return [];
  const limited = signals.slice(0, 3);
  return limited.map((signal) => ({
    id: randomUUID(),
    title: `Verify: ${signal}`,
    status: "pending" as const,
    tool: "none" as const,
    expectedObservation: null,
    successCriteria: null,
    phase: "verify" as const,
    priority: null,
    dependsOn: null,
    attempts: 0,
    maxAttempts: maxStepAttempts,
  }));
}

export function buildPlanStepsFromSpecs(
  stepSpecs: Array<{
    title?: string;
    tool?: string;
    expectedObservation?: string;
    successCriteria?: string;
    phase?: string;
    priority?: number;
    dependsOn?: number[] | string[];
    goalId?: string | null;
    subgoalId?: string | null;
  }>,
  meta?: PlannerMeta | null,
  includeSafety = false,
  maxStepAttempts = MAX_STEP_ATTEMPTS
): PlanStep[] {
  const preflightSteps = includeSafety
    ? buildSafetyCheckSteps(meta ?? undefined, maxStepAttempts)
    : [];
  const plannedSteps: PlanStep[] = stepSpecs.map((step, _index) => ({
    id: randomUUID(),
    title: step.title?.trim() || "Review the page state.",
    status: "pending" as const,
    tool: step.tool === "none" ? "none" : "playwright",
    expectedObservation: step.expectedObservation?.trim() || null,
    successCriteria: step.successCriteria?.trim() || null,
    goalId: step.goalId ?? null,
    subgoalId: step.subgoalId ?? null,
    phase: normalizePhase(step.phase),
    priority: typeof step.priority === "number" ? step.priority : null,
    dependsOn: normalizeDependencies(step.dependsOn, stepSpecs),
    attempts: 0,
    maxAttempts: maxStepAttempts,
  }));
  const verificationSteps = includeSafety
    ? buildVerificationSteps(meta ?? undefined, maxStepAttempts)
    : [];
  return [...preflightSteps, ...plannedSteps, ...verificationSteps];
}

export function buildBranchStepsFromAlternatives(
  alternatives: PlannerAlternative[] | undefined,
  maxStepAttempts: number,
  maxSteps: number
) {
  if (!alternatives?.length) return [];
  const specs = alternatives.flatMap((alt) => {
    if (alt.steps?.length) {
      return alt.steps.map((step) => ({
        ...step,
        phase: step.phase ?? "recover",
      }));
    }
    if (alt.title?.trim()) {
      return [
        {
          title: alt.title.trim(),
          tool: "playwright",
          phase: "recover",
        },
      ];
    }
    return [];
  });
  if (specs.length === 0) return [];
  return buildPlanStepsFromSpecs(specs, null, true, maxStepAttempts).slice(
    0,
    maxSteps
  );
}

export function normalizePhase(value?: string) {
  if (!value) return null;
  const normalized = value.toLowerCase();
  if (normalized === "observe") return "observe";
  if (normalized === "act") return "act";
  if (normalized === "verify") return "verify";
  if (normalized === "recover") return "recover";
  return null;
}

export function normalizeDependencies(
  value: number[] | string[] | undefined,
  stepSpecs: Array<{ title?: string }>
) {
  if (!Array.isArray(value) || value.length === 0) return null;
  if (typeof value[0] === "number") {
    return (value as number[])
      .filter(
        (idx) => Number.isInteger(idx) && idx >= 0 && idx < stepSpecs.length
      )
      .map((idx) => `step-${idx}`);
  }
  if (typeof value[0] === "string") {
    const names = value as string[];
    return names
      .map((name) => name.trim())
      .filter(Boolean)
      .map((name) => {
        const found = stepSpecs.findIndex(
          (spec) => spec.title?.trim().toLowerCase() === name.toLowerCase()
        );
        return found >= 0 ? `step-${found}` : null;
      })
      .filter(Boolean) as string[];
  }
  return null;
}

export function normalizePlanHierarchy(parsed: {
  goals?: Array<{
    title?: string;
    successCriteria?: string;
    priority?: number;
    dependsOn?: number[] | string[];
    subgoals?: Array<{
      title?: string;
      successCriteria?: string;
      priority?: number;
      dependsOn?: number[] | string[];
      steps?: Array<{
        title?: string;
        tool?: string;
        expectedObservation?: string;
        successCriteria?: string;
        phase?: string;
        priority?: number;
        dependsOn?: number[] | string[];
      }>;
    }>;
  }>;
}): PlanHierarchy | null {
  if (!Array.isArray(parsed.goals) || parsed.goals.length === 0) {
    return null;
  }
  const goals: PlanHierarchy["goals"] = parsed.goals.map((goal) => {
    const goalId = randomUUID();
    const subgoals = Array.isArray(goal.subgoals) ? goal.subgoals : [];
    return {
      id: goalId,
      title: goal.title?.trim() || "Primary objective",
      successCriteria: goal.successCriteria?.trim() || null,
      priority: typeof goal.priority === "number" ? goal.priority : null,
      dependsOn: Array.isArray(goal.dependsOn) ? goal.dependsOn : null,
      subgoals: subgoals.map((subgoal) => {
        const subgoalId = randomUUID();
        const steps = Array.isArray(subgoal.steps) ? subgoal.steps : [];
        return {
          id: subgoalId,
          title: subgoal.title?.trim() || "Supporting task",
          successCriteria: subgoal.successCriteria?.trim() || null,
          priority:
            typeof subgoal.priority === "number" ? subgoal.priority : null,
          dependsOn: Array.isArray(subgoal.dependsOn)
            ? subgoal.dependsOn
            : null,
          steps: steps.map((step) => ({
            title: step.title?.trim() || "Review the page state.",
            tool: step.tool === "none" ? "none" : "playwright",
            expectedObservation: step.expectedObservation?.trim() || null,
            successCriteria: step.successCriteria?.trim() || null,
            phase: step.phase ?? null,
            priority: step.priority ?? null,
            dependsOn: step.dependsOn ?? null,
          })),
        };
      }),
    };
  });
  return { goals };
}

export function flattenPlanHierarchy(hierarchy: PlanHierarchy) {
  const steps: Array<{
    title: string;
    tool?: "playwright" | "none";
    expectedObservation?: string | null;
    successCriteria?: string | null;
    phase?: string | null;
    priority?: number | null;
    dependsOn?: number[] | string[] | null;
    goalId?: string | null;
    subgoalId?: string | null;
  }> = [];
  for (const goal of hierarchy.goals) {
    for (const subgoal of goal.subgoals) {
      for (const step of subgoal.steps) {
        const priority =
          typeof step.priority === "number"
            ? step.priority
            : typeof subgoal.priority === "number"
              ? subgoal.priority
              : typeof goal.priority === "number"
                ? goal.priority
                : null;
        steps.push({
          ...step,
          priority,
          goalId: goal.id,
          subgoalId: subgoal.id,
        });
      }
    }
  }
  return steps;
}

export function decideNextAction(
  prompt: string,
  memory: string[]
): AgentDecision {
  const lower = prompt.toLowerCase();
  if (lower.includes("browse") || lower.includes("website")) {
    return {
      action: "tool",
      reason: "Prompt implies browser automation.",
      toolName: "playwright",
    };
  }
  if (
    lower.includes("login") ||
    lower.includes("log in") ||
    lower.includes("sign in") ||
    lower.includes("signin")
  ) {
    return {
      action: "tool",
      reason: "Prompt includes a login flow.",
      toolName: "playwright",
    };
  }

  if (memory.length > 0) {
    return {
      action: "respond",
      reason: "Sufficient context to respond in scaffold.",
    };
  }

  return {
    action: "wait_human",
    reason: "Not enough context; human input required.",
  };
}

export function buildPlan(prompt: string, maxSteps = MAX_PLAN_STEPS): string[] {
  const normalized = prompt.trim();
  if (!normalized) return [];
  const lower = normalized.toLowerCase();
  const steps: string[] = [];

  if (
    lower.includes("login") ||
    lower.includes("log in") ||
    lower.includes("sign in") ||
    lower.includes("signin")
  ) {
    steps.push("Open the target website.");
    steps.push("Locate the sign-in form.");
    steps.push("Fill in the credentials.");
    steps.push("Submit the form and wait for the next page.");
    steps.push("Verify the expected page or account state.");
  } else if (lower.includes("browse") || lower.includes("website")) {
    steps.push("Open the target URL.");
    steps.push("Wait for the page to finish loading.");
    steps.push("Locate the requested content.");
    steps.push("Capture the relevant details.");
  } else {
    const sentences = normalized
      .split(/[.!?]\s+/)
      .map((sentence) => sentence.trim())
      .filter(Boolean);
    for (const sentence of sentences) {
      steps.push(sentence);
      if (steps.length >= maxSteps) break;
    }
  }

  return steps.slice(0, maxSteps);
}

export function normalizeDecision(
  decision: Partial<AgentDecision> | undefined,
  steps: PlanStep[],
  prompt: string,
  memory: string[]
): AgentDecision {
  if (decision?.action === "tool") {
    return {
      action: "tool",
      reason: decision.reason ?? "LLM planner selected tool execution.",
      toolName: decision.toolName ?? "playwright",
    };
  }
  if (decision?.action === "respond") {
    return {
      action: "respond",
      reason: decision.reason ?? "LLM planner selected response.",
    };
  }
  if (decision?.action === "wait_human") {
    return {
      action: "wait_human",
      reason: decision.reason ?? "LLM planner requires human input.",
    };
  }
  if (steps.length > 0) {
    return {
      action: "tool",
      reason: "Plan generated; execute tool steps.",
      toolName: "playwright",
    };
  }
  return decideNextAction(prompt, memory);
}

export function shouldEvaluateReplan(
  stepIndex: number,
  steps: PlanStep[],
  replanEverySteps: number
) {
  if (steps.length < 3) return false;
  const nextIndex = stepIndex + 1;
  if (nextIndex >= steps.length) return false;
  return nextIndex % replanEverySteps === 0;
}

export function appendTaskTypeToPrompt(
  prompt: string,
  taskType: PlannerMeta["taskType"] | null
) {
  if (!taskType) return prompt;
  return `${prompt}\n\nTask type: ${taskType}`;
}

export function isExtractionStep(
  step: PlanStep,
  prompt: string,
  taskType: PlannerMeta["taskType"] | null
) {
  if (taskType === "extract_info") return true;
  const combined =
    `${step.title} ${step.expectedObservation ?? ""} ${prompt}`.toLowerCase();
  const mentionsExtract = /(extract|collect|find|list|get)\b/.test(combined);
  const mentionsTarget = /(product|email)/.test(combined);
  return mentionsExtract && mentionsTarget;
}

import prisma from "@/shared/lib/db/prisma";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { internalError } from "@/shared/errors/app-error";
import { apiHandlerWithParams } from "@/shared/lib/api/api-handler";

export const runtime = "nodejs";
const DEBUG_CHATBOT = process.env.DEBUG_CHATBOT === "true";

async function GET_handler(
  req: Request,
  { params }: { params: Promise<{ runId: string }> }
) {
  try {
    if (!("agentBrowserSnapshot" in prisma)) {
      return createErrorResponse(internalError("Agent snapshots not initialized."), {
        request: req,
        source: "chatbot.agent.[runId].stream.GET",
      });
    }
    const { runId } = await params;
    const encoder = new TextEncoder();
    let timer: NodeJS.Timeout | null = null;

    const stream = new ReadableStream({
      async start(controller) {
        const sendSnapshot = async () => {
          try {
            const latest = await prisma.agentBrowserSnapshot.findFirst({
              where: { runId },
              orderBy: { createdAt: "desc" },
            });
            const payload = latest ? { snapshot: latest } : { snapshot: null };
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify(payload)}\n\n`)
            );
          } catch (error) {
            if (DEBUG_CHATBOT) {
              console.error("[chatbot][agent][stream] Snapshot fetch failed", {
                runId,
                error,
              });
            }
            controller.enqueue(
              encoder.encode(
                `data: ${JSON.stringify({ snapshot: null, error: "snapshot" })}\n\n`
              )
            );
          }
        };

        await sendSnapshot();
        timer = setInterval(() => { void sendSnapshot(); }, 2000);

        req.signal.addEventListener("abort", () => {
          if (timer) {
            clearInterval(timer);
          }
          controller.close();
        });
      },
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache, no-transform",
        Connection: "keep-alive",
      },
    });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "chatbot.agent.[runId].stream.GET",
      fallbackMessage: "Failed to stream snapshots",
    });
  }
}

export const GET = apiHandlerWithParams<{ runId: string }>(async (req, _ctx, params) => GET_handler(req, { params: Promise.resolve(params) }), { source: "chatbot.agent.[runId].stream.GET" });

"use client";

import { Button, Input, Label, Textarea, Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/shared/ui";
import React from "react";





import type { AiNode, NodeConfig, RuntimeState } from "@/features/ai-paths/lib";
import {
  DEFAULT_CONTEXT_ROLE,
  applyContextPreset,
  formatRuntimeValue,
  getContextPresetSet,
  parsePathList,
  safeStringify,
  toggleContextTarget,
} from "@/features/ai-paths/lib";

function pruneLargeFields(value: unknown, seen = new Set<object>()): unknown {
  if (!value || typeof value !== "object") return value;
  if (seen.has(value)) return "[Circular]";
  seen.add(value);
  if (Array.isArray(value)) {
    return value.map((item) => pruneLargeFields(item, seen));
  }
  const result: Record<string, unknown> = {};
  for (const [key, val] of Object.entries(value)) {
    if (typeof val === "string" && val.length > 1000) {
      result[key] = `${val.substring(0, 1000)}... [truncated, ${val.length} chars]`;
    } else {
      result[key] = pruneLargeFields(val, seen);
    }
  }
  return result;
}

function sanitizePayload(value: unknown, hideLargeFields: boolean): unknown {
  return hideLargeFields ? pruneLargeFields(value) : value;
}

type ContextNodeConfigSectionProps = {
  selectedNode: AiNode;
  runtimeState: RuntimeState;
  updateSelectedNodeConfig: (patch: Partial<NodeConfig>) => void;
  toast: (message: string, options?: { variant?: "success" | "error" }) => void;
};

export function ContextNodeConfigSection({
  selectedNode,
  runtimeState,
  updateSelectedNodeConfig,
  toast,
}: ContextNodeConfigSectionProps) {
  const [hideLargeFields, setHideLargeFields] = React.useState(true);
  const [showDiff, setShowDiff] = React.useState(true);
  const [diffOnlyChanges, setDiffOnlyChanges] = React.useState(true);

  if (selectedNode.type !== "context") return null;

  const contextConfig = selectedNode.config?.context ?? {
    role: DEFAULT_CONTEXT_ROLE,
    entityType: "product",
    entityIdSource: "simulation",
    entityId: "",
    scopeMode: "full",
    scopeTarget: "entity",
    includePaths: [],
    excludePaths: [],
  };
  const presetSet = getContextPresetSet(contextConfig.entityType);
  const receivedInputs = runtimeState.inputs[selectedNode.id] ?? {};
  const resolvedOutputs = runtimeState.outputs[selectedNode.id] ?? {};

  const stringifyPayload = (value: unknown): string => {
    if (value === undefined) return "";
    if (typeof value === "string") return value;
    try {
      return JSON.stringify(value, null, 2);
    } catch {
      return safeStringify(value);
    }
  };
  const receivedContext = sanitizePayload(receivedInputs["context"], hideLargeFields);
  const sanitizedInputs = sanitizePayload(receivedInputs, hideLargeFields) as Record<string, unknown>;
  const sanitizedOutputs = sanitizePayload(resolvedOutputs, hideLargeFields) as Record<string, unknown>;
  const receivedContextText = stringifyPayload(receivedContext);
  const receivedInputsText = stringifyPayload(sanitizedInputs);
  const resolvedOutputsText = stringifyPayload(sanitizedOutputs);
  const resolvedEntityId =
    typeof sanitizedOutputs?.entityId === "string"
      ? (sanitizedOutputs.entityId)
      : "";
  const resolvedEntityType =
    typeof sanitizedOutputs?.entityType === "string"
      ? (sanitizedOutputs.entityType)
      : "";
  const diffInputs = sanitizedInputs ?? {};
  const diffOutputs = sanitizedOutputs ?? {};
  const diffKeys = Array.from(
    new Set([
      ...Object.keys(diffInputs ?? {}),
      ...Object.keys(diffOutputs ?? {}),
    ])
  ).sort();
  const diff = diffKeys.reduce<{
    added: string[];
    removed: string[];
    changed: string[];
    same: string[];
  }>(
    (acc, key) => {
      const inInput = key in diffInputs;
      const inOutput = key in diffOutputs;
      if (!inInput && inOutput) {
        acc.added.push(key);
        return acc;
      }
      if (inInput && !inOutput) {
        acc.removed.push(key);
        return acc;
      }
      const inputValue = diffInputs[key];
      const outputValue = diffOutputs[key];
      const inputString = stringifyPayload(inputValue);
      const outputString = stringifyPayload(outputValue);
      if (inputString !== outputString) {
        acc.changed.push(key);
      } else {
        acc.same.push(key);
      }
      return acc;
    },
    { added: [], removed: [], changed: [], same: [] }
  );
  const diffLines = [
    ...diff.added.map(
      (key) => `+ ${key}: ${formatRuntimeValue(diffOutputs[key])}`
    ),
    ...diff.removed.map(
      (key) => `- ${key}: ${formatRuntimeValue(diffInputs[key])}`
    ),
    ...diff.changed.map(
