const ensureModels = () => {
  if (!prismaAny.aiPathRun || !prismaAny.aiPathRunNode || !prismaAny.aiPathRunEvent) {
    throw new Error("AiPath run models not initialized in Prisma.");
  }
};

export const prismaPathRunRepository: AiPathRunRepository = {
  async createRun(input: AiPathRunCreateInput) {
    ensureModels();
    const run = await prismaAny.aiPathRun!.create({
      data: {
        pathId: input.pathId,
        pathName: input.pathName ?? null,
        status: "queued",
        triggerEvent: input.triggerEvent ?? null,
        triggerNodeId: input.triggerNodeId ?? null,
        triggerContext: input.triggerContext ?? null,
        graph: input.graph ?? null,
        runtimeState: input.runtimeState ?? null,
        meta: input.meta ?? null,
        entityId: input.entityId ?? null,
        entityType: input.entityType ?? null,
        retryCount: input.retryCount ?? 0,
        maxAttempts: input.maxAttempts ?? 3,
        nextRetryAt: input.nextRetryAt ?? null,
      },
    });
    return mapRun(run);
  },

  async updateRun(runId: string, data: AiPathRunUpdate) {
    ensureModels();
    const run = await prismaAny.aiPathRun!.update({
      where: { id: runId },
      data: data as Record<string, unknown>,
    });
    return mapRun(run);
  },

  async findRunById(runId: string) {
    ensureModels();
    const run = await prismaAny.aiPathRun!.findUnique({
      where: { id: runId },
    });
    return run ? mapRun(run) : null;
  },

  async listRuns(options: AiPathRunListOptions = {}) {
    ensureModels();
    const where = {
      ...(options.pathId ? { pathId: options.pathId } : {}),
      ...(options.status ? { status: options.status } : {}),
    };
    const [runs, total] = await Promise.all([
      prismaAny.aiPathRun!.findMany({
        where,
        orderBy: { createdAt: "desc" },
        ...(typeof options.offset === "number" ? { skip: options.offset } : {}),
        ...(typeof options.limit === "number" ? { take: options.limit } : {}),
      }),
      prismaAny.aiPathRun!.count({ where }),
    ]);
    return { runs: runs.map(mapRun), total };
  },

  async claimNextQueuedRun() {
    ensureModels();
    const now = new Date();
    const run = (await prismaAny.aiPathRun!.findFirst({
      where: {
        status: "queued",
        OR: [{ nextRetryAt: null }, { nextRetryAt: { lte: now } }],
      },
      orderBy: { createdAt: "asc" },
    })) as Record<string, unknown> | null;
    if (!run) return null;
    const updated = await prismaAny.aiPathRun!.update({
      where: { id: run.id },
      data: { status: "running", startedAt: new Date() },
    });
    return mapRun(updated);
  },

  async createRunNodes(runId, nodes) {
    ensureModels();
    if (!nodes || nodes.length === 0) return;
    const data = nodes.map((node) => ({
      runId,
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title ?? null,
      status: "pending",
      attempt: 0,
    }));
    await prismaAny.aiPathRunNode!.createMany({ data });
  },

  async upsertRunNode(runId, nodeId, data) {
    ensureModels();
    const node = await prismaAny.aiPathRunNode!.upsert({
      where: { runId_nodeId: { runId, nodeId } },
      update: data as Record<string, unknown>,
      create: {
        runId,
        nodeId,
        nodeType: data.nodeType,
        nodeTitle: data.nodeTitle ?? null,
        status: data.status ?? "pending",
        attempt: data.attempt ?? 0,
        inputs: data.inputs ?? null,
        outputs: data.outputs ?? null,
        errorMessage: data.errorMessage ?? null,
        startedAt: data.startedAt ?? null,
        finishedAt: data.finishedAt ?? null,
      },
    });
    return mapNode(node);
  },

  async listRunNodes(runId: string) {
    ensureModels();
    const nodes = await prismaAny.aiPathRunNode!.findMany({
      where: { runId },
      orderBy: { createdAt: "asc" },
    });
    return nodes.map(mapNode);
  },

  async createRunEvent(input: AiPathRunEventCreateInput) {
    ensureModels();
    const event = await prismaAny.aiPathRunEvent!.create({
      data: {
        runId: input.runId,
        level: input.level,
        message: input.message,
        metadata: input.metadata ?? null,
      },
    });
    return mapEvent(event);
  },

  async listRunEvents(runId: string) {
    ensureModels();
    const events = await prismaAny.aiPathRunEvent!.findMany({
      where: { runId },
      orderBy: { createdAt: "asc" },
    });
    return events.map(mapEvent);
  },

  async markStaleRunningRuns(maxAgeMs: number) {
    ensureModels();
    const cutoff = new Date(Date.now() - maxAgeMs);
    const result = await prismaAny.aiPathRun!.updateMany({
      where: { status: "running", startedAt: { lt: cutoff } },
      data: {
        status: "failed",
        finishedAt: new Date(),
        errorMessage: "Run marked failed due to stale running state.",
      },
    });
    return { count: (result as { count?: number }).count ?? 0 };
  },
};

import type { NextAuthConfig } from "next-auth";

const secret = process.env.AUTH_SECRET || process.env.NEXTAUTH_SECRET;

// Basic config that is edge-compatible
const adminOnlyPrefixes = ["/admin/auth", "/admin/products"];
const elevatedRoles = new Set(["admin", "super_admin", "superuser"]);

const permissionRules: Array<{ prefix: string; permissions: string[] }> = [
  { prefix: "/admin/auth/permissions", permissions: ["auth.users.write"] },
  { prefix: "/admin/auth/settings", permissions: ["auth.users.write"] },
  { prefix: "/admin/auth/users", permissions: ["auth.users.write"] },
  { prefix: "/admin/auth", permissions: ["auth.users.read"] },
  { prefix: "/admin/products", permissions: ["products.manage"] },
  { prefix: "/admin/drafts", permissions: ["products.manage"] },
  { prefix: "/admin/notes", permissions: ["notes.manage"] },
  { prefix: "/admin/chatbot", permissions: ["chatbot.manage"] },
  { prefix: "/admin/agentcreator", permissions: ["chatbot.manage"] },
  { prefix: "/admin/integrations", permissions: ["settings.manage"] },
  { prefix: "/admin/system", permissions: ["settings.manage"] },
  { prefix: "/admin/settings", permissions: ["settings.manage"] },
  { prefix: "/admin/files", permissions: ["settings.manage"] },
  { prefix: "/admin/databases", permissions: ["settings.manage"] },
  { prefix: "/admin/front-manage", permissions: ["settings.manage"] },
  { prefix: "/admin/cms", permissions: ["settings.manage"] },
];

const resolveRequiredPermissions = (pathname: string) => {
  for (const rule of permissionRules) {
    if (pathname.startsWith(rule.prefix)) {
      return rule.permissions;
    }
  }
  return [];
};

export const authConfig = {
  providers: [], // Providers will be added in the main auth.ts or passed here
  pages: {
    signIn: "/auth/signin",
  },
  trustHost: true,
  ...(secret ? { secret } : {}),
  session: { strategy: "jwt" },
  callbacks: {
    authorized({ auth, request: { nextUrl } }) {
      const isLoggedIn = !!auth?.user;
      const isOnAdmin = nextUrl.pathname.startsWith("/admin");
      if (isOnAdmin) {
        if (!isLoggedIn) return false;
        const authUser = auth?.user as {
          role?: string;
          isElevated?: boolean;
          accountDisabled?: boolean;
          accountBanned?: boolean;
        };
        const role = authUser?.role ?? "unknown";
        const isElevated = authUser?.isElevated ?? elevatedRoles.has(role);
        if (authUser?.accountBanned || authUser?.accountDisabled) {
          const redirectUrl = new URL("/auth/signin", nextUrl);
          redirectUrl.searchParams.set("error", "AccountDisabled");
          return Response.redirect(redirectUrl);
        }
        if (adminOnlyPrefixes.some((prefix) => nextUrl.pathname.startsWith(prefix))) {
          if (!isElevated) {
            const redirectUrl = new URL("/admin", nextUrl);
            redirectUrl.searchParams.set("denied", "1");
            return Response.redirect(redirectUrl);
          }
          return true;
        }

        const requiredPermissions = resolveRequiredPermissions(nextUrl.pathname);
        if (requiredPermissions.length === 0) return true;
        const permissions = (auth?.user as { permissions?: string[] })?.permissions ?? [];
        const hasAccess =
          isElevated ||
          requiredPermissions.some((permission) => permissions.includes(permission));
        if (hasAccess) return true;
        const redirectUrl = new URL("/admin", nextUrl);
        redirectUrl.searchParams.set("denied", "1");
        return Response.redirect(redirectUrl);
      }
      return true;
    },
    session({ session, token }) {
      if (session.user) {
        session.user.id = token.sub ?? session.user.id;
        session.user.role = (token as { role?: string }).role ?? null;
        session.user.permissions =
          (token as { permissions?: string[] }).permissions ?? [];
        session.user.roleLevel = (token as { roleLevel?: number }).roleLevel ?? null;
        session.user.isElevated = (token as { isElevated?: boolean }).isElevated ?? false;
        session.user.accountDisabled =
          (token as { accountDisabled?: boolean }).accountDisabled ?? false;
        session.user.accountBanned =
          (token as { accountBanned?: boolean }).accountBanned ?? false;
      }
      return session;
    },
  },
} satisfies NextAuthConfig;

import "server-only";

import { ErrorSystem } from "@/features/observability/server";
import NextAuth, { type Session, type User } from "next-auth";
import type { JWT } from "next-auth/jwt";
import Credentials from "next-auth/providers/credentials";
import Google from "next-auth/providers/google";
import Facebook from "next-auth/providers/facebook";
import type { Provider } from "next-auth/providers";
import { PrismaAdapter } from "@auth/prisma-adapter";
import { MongoDBAdapter } from "@auth/mongodb-adapter";
import bcrypt from "bcryptjs";
import prisma from "@/shared/lib/db/prisma";
import { getMongoClient } from "@/shared/lib/db/mongo-client";
import { getAuthDataProvider } from "@/features/auth/services/auth-provider";
import { findAuthUserByEmail, findAuthUserById } from "@/features/auth/services/auth-user-repository";
import { getAuthAccessForUser } from "@/features/auth/services/auth-access";
import {
  checkLoginAllowed,
  extractClientIp,
  recordLoginFailure,
  recordLoginSuccess,
} from "@/features/auth/services/auth-security";
import { getAuthUserPageSettings } from "@/features/auth/services/auth-settings";
import { getAuthSecurityProfile, updateAuthSecurityProfile } from "@/features/auth/services/auth-security-profile";
import { consumeLoginChallenge } from "@/features/auth/services/auth-login-challenge";
import { decryptAuthSecret } from "@/features/auth/utils/auth-encryption";
import { hashRecoveryCode, verifyTotpToken } from "@/features/auth/services/totp";
import { authConfig } from "./auth.config";

const credentialsProvider = Credentials({
  name: "Credentials",
  credentials: {
    email: { label: "Email", type: "email" },
    password: { label: "Password", type: "password" },
    otp: { label: "One-time code", type: "text" },
    recoveryCode: { label: "Recovery code", type: "text" },
    challengeId: { label: "Challenge", type: "text" },
  },
  async authorize(credentials, request) {
    try {
      const email = credentials?.email?.toString() ?? "";
      const password = credentials?.password?.toString() ?? "";
      const otp = credentials?.otp?.toString() ?? "";
      const recoveryCode = credentials?.recoveryCode?.toString() ?? "";
      const challengeId = credentials?.challengeId?.toString() ?? "";
      if (!email || !password) {
        console.log("[AUTH] Missing email or password");
        return null;
      }
      const ip = extractClientIp(request);
      const allowed = await checkLoginAllowed({ email, ip });
      if (!allowed.allowed) {
        await ErrorSystem.logWarning("[AUTH] Login blocked due to rate limits", {
          service: "auth",
          email,
          ip,
          lockedUntil: allowed.lockedUntil?.toISOString(),
        });
        return null;
      }

      if (challengeId) {
        const challenge = await consumeLoginChallenge({
          id: challengeId,
          email,
          ip,
        });
        if (challenge) {
          const user = await findAuthUserById(challenge.userId);
          if (!user) {
            await recordLoginFailure({ email, ip, request });
            return null;
          }

          const security = await getAuthSecurityProfile(user.id);
          const settings = await getAuthUserPageSettings();

          if (security.bannedAt) {
            await recordLoginFailure({ email, ip, request });
            return null;
          }
          if (security.disabledAt) {
            await recordLoginFailure({ email, ip, request });
            return null;
          }
          if (
            settings.requireEmailVerification &&
            !user.emailVerified
          ) {
            await recordLoginFailure({ email, ip, request });
            return null;
          }
          if (security.allowedIps.length > 0 && ip) {
            const allowedSet = new Set(security.allowedIps);
            if (!allowedSet.has(ip)) {
              await recordLoginFailure({ email, ip, request });
              return null;
            }
          }

          if (security.mfaEnabled) {
            const providedRecovery = recoveryCode.trim();
            const providedOtp = otp.trim();
            let mfaOk = false;
            if (providedRecovery) {
              const hashed = hashRecoveryCode(providedRecovery);
              if (security.recoveryCodes.includes(hashed)) {
                const nextCodes = security.recoveryCodes.filter(
                  (code) => code !== hashed
                );
                await updateAuthSecurityProfile(user.id, {
                  recoveryCodes: nextCodes,
                });
                mfaOk = true;
              }
            } else if (providedOtp && security.mfaSecret) {
              const secret = decryptAuthSecret(security.mfaSecret);
              mfaOk = verifyTotpToken(secret, providedOtp);
            }
            if (!mfaOk) {
              await recordLoginFailure({ email, ip, request });
              return null;
            }
          }

          await recordLoginSuccess({ email, ip, request, userId: user.id });
          return {
            id: user.id,
            email: user.email,
            name: user.name ?? null,
            image: user.image ?? null,
          };
        }
      }

      await ErrorSystem.logInfo("[AUTH] Attempting to find user", { service: "auth", email });

      // findAuthUserByEmail uses getAuthDataProvider() internally to choose DB
      const user = await findAuthUserByEmail(email);

      if (!user) {
        await ErrorSystem.logInfo("[AUTH] User not found", { service: "auth", email });
        await recordLoginFailure({ email, ip, request });
        return null;
      }

      const security = await getAuthSecurityProfile(user.id);
      const settings = await getAuthUserPageSettings();

      if (security.bannedAt) {
        await recordLoginFailure({ email, ip, request });
        return null;
      }
      if (security.disabledAt) {
        await recordLoginFailure({ email, ip, request });
        return null;
      }
      if (settings.requireEmailVerification && !user.emailVerified) {
        await recordLoginFailure({ email, ip, request });
        return null;
      }
      if (security.allowedIps.length > 0 && ip) {
        const allowedSet = new Set(security.allowedIps);
        if (!allowedSet.has(ip)) {
          await recordLoginFailure({ email, ip, request });
          return null;
        }
      }

      if (!user.passwordHash) {
        console.log("[AUTH] User has no password hash");
        await recordLoginFailure({ email, ip, request });
        return null;
      }

      console.log(`[AUTH] User found: ${user.id}. Hash len: ${user.passwordHash.length}. Input pass len: ${password.length}`);
      const isValid = await bcrypt.compare(password, user.passwordHash);
      console.log("[AUTH] Password valid:", isValid);

      if (!isValid) {
        await recordLoginFailure({ email, ip, request });
        return null;
      }

      if (security.mfaEnabled) {
        const providedRecovery = recoveryCode.trim();
        const providedOtp = otp.trim();
        let mfaOk = false;
        if (providedRecovery) {
          const hashed = hashRecoveryCode(providedRecovery);
          if (security.recoveryCodes.includes(hashed)) {
            const nextCodes = security.recoveryCodes.filter(
              (code) => code !== hashed
            );
            await updateAuthSecurityProfile(user.id, {
              recoveryCodes: nextCodes,
            });
            mfaOk = true;
          }
        } else if (providedOtp && security.mfaSecret) {
          const secret = decryptAuthSecret(security.mfaSecret);
          mfaOk = verifyTotpToken(secret, providedOtp);
        }
        if (!mfaOk) {
          await recordLoginFailure({ email, ip, request });
          return null;
        }
      }

      await recordLoginSuccess({ email, ip, request, userId: user.id });

      return {
        id: user.id,
        email: user.email,
        name: user.name ?? null,
        image: user.image ?? null,
      };
    } catch (error) {
      await ErrorSystem.captureException(error, {
        service: "auth",
        action: "authorize",
      });
      return null;
    }
  },
});

const buildProviders = () => {
  const providers: Provider[] = [credentialsProvider];

  if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
    providers.push(
      Google({
        clientId: process.env.GOOGLE_CLIENT_ID,
        clientSecret: process.env.GOOGLE_CLIENT_SECRET,
      })
    );
  } else {
    // Non-critical warning, log to system but don't spam if not configured
    // We can use console.warn or ErrorSystem.logWarning
    console.warn("[AUTH] Google Client ID/Secret not found. Google login will be unavailable.");
  }

  if (process.env.FACEBOOK_CLIENT_ID && process.env.FACEBOOK_CLIENT_SECRET) {
    providers.push(
      Facebook({
        clientId: process.env.FACEBOOK_CLIENT_ID,
        clientSecret: process.env.FACEBOOK_CLIENT_SECRET,
      })
    );
  } else {
    console.warn("[AUTH] Facebook Client ID/Secret not found. Facebook login will be unavailable.");
  }

  return providers;
};

const buildAuthConfig = async () => {
  try {
    await ErrorSystem.logInfo("[AUTH] Starting configuration...", { service: "auth" });
    const provider = await getAuthDataProvider();
    console.log("[AUTH] Provider determined:", provider);
    const hasMongo = Boolean(process.env.MONGODB_URI);
    const hasPrisma = Boolean(process.env.DATABASE_URL);

    let adapter;
    if (provider === "mongodb" && hasMongo) {
      adapter = MongoDBAdapter(getMongoClient(), {
        databaseName: process.env.MONGODB_DB ?? "app",
      });
    } else if (provider === "mongodb" && !hasMongo && hasPrisma) {
      console.warn("[AUTH] MongoDB provider selected but MONGODB_URI missing. Falling back to Prisma.");
      adapter = PrismaAdapter(prisma);
    } else if (hasPrisma) {
      adapter = PrismaAdapter(prisma);
    } else {
      adapter = undefined;
    }

    if (!adapter) {
      console.warn("[AUTH] No adapter configured. Environment:", { hasMongo, hasPrisma, provider });
    } else {
      console.log(`[AUTH] Adapter configured for ${provider}.`);
    }

    return {
      ...authConfig,
      ...(adapter && { adapter }),
      providers: buildProviders(),
      callbacks: {
        ...(authConfig.callbacks ?? {}),
        async jwt({ token, user }: { token: JWT; user?: User }) {
          const userId = user?.id ?? token.sub;
          if (userId) {
            const access = await getAuthAccessForUser(userId);
            token.role = access.roleId;
            token.permissions = access.permissions;
            token.roleLevel = access.level;
            token.isElevated = access.isElevated;
            const security = await getAuthSecurityProfile(userId);
            token.accountDisabled = Boolean(security.disabledAt);
            token.accountBanned = Boolean(security.bannedAt);
          }
          return token;
        },
        session({ session, token }: { session: Session; token: JWT }) {
          if (session.user) {
            if (token.sub) {
              session.user.id = token.sub;
            }
            session.user.role = (token.role as string) ?? null;
            session.user.permissions = (token.permissions as string[]) ?? [];
            session.user.roleLevel = (token.roleLevel as number) ?? null;
            session.user.isElevated = (token.isElevated as boolean) ?? false;
            session.user.accountDisabled = (token.accountDisabled as boolean) ?? false;
            session.user.accountBanned = (token.accountBanned as boolean) ?? false;
          }
          return session;
        },
      },
      debug: true,
    };
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "auth",
      action: "configuration",
    });
    throw error;
  }
};

const AUTH_CONFIG_TTL_MS = 30_000;
let cachedAuthConfig: Awaited<ReturnType<typeof buildAuthConfig>> | null = null;
let cachedAuthConfigAt = 0;
let cachedAuthConfigPromise: Promise<Awaited<ReturnType<typeof buildAuthConfig>>> | null = null;

const getAuthConfig = async () => {
  const now = Date.now();
  if (cachedAuthConfig && now - cachedAuthConfigAt < AUTH_CONFIG_TTL_MS) {
    return cachedAuthConfig;
  }
  if (cachedAuthConfigPromise) {
    return cachedAuthConfigPromise;
  }
  cachedAuthConfigPromise = buildAuthConfig()
    .then((config) => {
      cachedAuthConfig = config;
      cachedAuthConfigAt = Date.now();
      return config;
    })
    .finally(() => {
      cachedAuthConfigPromise = null;
    });
  return cachedAuthConfigPromise;
};

export const { handlers, auth, signIn, signOut } = NextAuth(getAuthConfig);

