export const prismaProductRepository: ProductRepository = {
  async getProducts(filters: ProductFilters) {
    const where = buildProductWhere(filters);
...async countProducts(filters: ProductFilters) {
    const where = buildProductWhere(filters);
    return prisma.product.count({ where });
  },

  async getProductById(id: string) {
    const product = await prisma.product.findUnique({
      where: { id },
      include: {
        images: {
          include: { imageFile: true },
          orderBy: { assignedAt: "desc" },
        },
        catalogs: {
          include: {
            catalog: {
              include: {
                languages: {
                  include: { language: true }
                }
              }
            }
          },
        },
      },
    });
    if (!product) return null;
    return {
      ...toProductRecord(product),
      images: product.images.map((image) => ({
        productId: image.productId,
        imageFileId: image.imageFileId,
        assignedAt: image.assignedAt,
        imageFile: toImageFileRecord(image.imageFile),
      })),
      catalogs: product.catalogs.map((entry) => ({
        productId: entry.productId,
        catalogId: entry.catalogId,
        assignedAt: entry.assignedAt,
        catalog: toCatalogRecord(entry.catalog),
      })),
    };
  },

  async getProductBySku(sku: string) {
    const product = await prisma.product.findUnique({ where: { sku } });
    if (!product) return null;
    return toProductRecord(product);
  },

  async findProductByBaseId(baseProductId: string) {
    const product = await prisma.product.findFirst({
      where: { baseProductId },
    });
    if (!product) return null;
    return toProductRecord(product);
  },

  async createProduct(data: CreateProductInput) {
    if (data.sku) {
      const existing = await prisma.product.findUnique({
        where: { sku: data.sku },
        select: { id: true },
      });
      if (existing) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku,
          productId: existing.id,
        });
      }
    }

    const cleanData = removeUndefined(data) as Prisma.ProductCreateInput;
    try {
      const product = await prisma.product.create({ data: cleanData });
      return toProductRecord(product);
    } catch (error) {
      if (
        error instanceof Prisma.PrismaClientKnownRequestError &&
        error.code === "P2002" &&
        Array.isArray(error.meta?.target) &&
        error.meta?.target.includes("sku")
      ) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku ?? null,
        });
      }
      throw error;
    }
  },

  async updateProduct(id: string, data: UpdateProductInput) {
    const productExists = await prisma.product.findUnique({ where: { id } });
    if (!productExists) return null;
    const cleanData = removeUndefined(data) as Prisma.ProductUpdateInput;
    const product = await prisma.product.update({ where: { id }, data: cleanData });
    return toProductRecord(product);
  },

  async deleteProduct(id: string) {
    const productExists = await prisma.product.findUnique({ where: { id } });
    if (!productExists) return null;
    const product = await prisma.product.delete({ where: { id } });
    return toProductRecord(product);
  },

  async duplicateProduct(id: string, sku: string) {
    const product = await prisma.product.findUnique({ where: { id } });
    if (!product) return null;

    const existingSku = await prisma.product.findUnique({
      where: { sku },
      select: { id: true },
    });
    if (existingSku) {
      throw conflictError("A product with this SKU already exists.", {
        sku,
        productId: existingSku.id,
      });
    }

    const duplicated = await prisma.product.create({
      data: {
        name_en: product.name_en,
        name_pl: product.name_pl,
        name_de: product.name_de,
        description_en: product.description_en,
        description_pl: product.description_pl,
        description_de: product.description_de,
        supplierName: product.supplierName,
        supplierLink: product.supplierLink,
        priceComment: product.priceComment,
        stock: product.stock,
        price: product.price,
        sizeLength: product.sizeLength,
        sizeWidth: product.sizeWidth,
        weight: product.weight,
        length: product.length,
        parameters: Array.isArray(product.parameters) ? product.parameters : [],
        imageLinks: Array.isArray(product.imageLinks) ? product.imageLinks : [],
        defaultPriceGroupId: product.defaultPriceGroupId ?? null,
        ean: product.ean ?? null,
        gtin: product.gtin ?? null,
        asin: product.asin ?? null,
        sku,
      },
    });
    return toProductRecord(duplicated);
  },

  async addProductImages(productId: string, imageFileIds: string[]) {
    if (imageFileIds.length === 0) return;
    await prisma.productImage.createMany({
      data: imageFileIds.map((imageFileId) => ({ productId, imageFileId })),
      skipDuplicates: true,
    });
  },

  async replaceProductCatalogs(productId: string, catalogIds: string[]) {
    await prisma.productCatalog.deleteMany({ where: { productId } });
    if (catalogIds.length === 0) return;
    const uniqueIds = Array.from(new Set(catalogIds));
    const existing = await prisma.catalog.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productCatalog.createMany({
      data: validIds.map((catalogId) => ({ productId, catalogId })),
    });
  },

  async replaceProductCategories(productId: string, categoryIds: string[]) {
    await prisma.productCategoryAssignment.deleteMany({ where: { productId } });
    if (categoryIds.length === 0) return;
    const uniqueIds = Array.from(new Set(categoryIds));
    const existing = await prisma.productCategory.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productCategoryAssignment.createMany({
      data: validIds.map((categoryId) => ({ productId, categoryId })),
    });
  },

  async replaceProductTags(productId: string, tagIds: string[]) {
    await prisma.productTagAssignment.deleteMany({ where: { productId } });
    if (tagIds.length === 0) return;
    const uniqueIds = Array.from(new Set(tagIds));
    const existing = await prisma.productTag.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productTagAssignment.createMany({
      data: validIds.map((tagId) => ({ productId, tagId })),
    });
  },

  async removeProductImage(productId: string, imageFileId: string) {
    await prisma.productImage.deleteMany({
      where: { productId, imageFileId },
    });
  },

  async countProductsByImageFileId(imageFileId: string) {
    return prisma.productImage.count({ where: { imageFileId } });
  },
};

"use client";

import { Effect, BlendFunction } from "postprocessing";
import { Uniform } from "three";
import { forwardRef, useMemo } from "react";

// Bayer 8x8 ordered dithering shader for black & white effect
const ditheringFragmentShader = `
  uniform float intensity;

  // Bayer 8x8 dithering matrix (normalized 0-1)
  float getBayerValue(vec2 coord) {
    int x = int(mod(coord.x, 8.0));
    int y = int(mod(coord.y, 8.0));

    // Bayer 8x8 matrix values (0-63 normalized to 0-1)
    int bayerMatrix[64] = int[64](
      0, 32, 8, 40, 2, 34, 10, 42,
      48, 16, 56, 24, 50, 18, 58, 26,
      12, 44, 4, 36, 14, 46, 6, 38,
      60, 28, 52, 20, 62, 30, 54, 22,
      3, 35, 11, 43, 1, 33, 9, 41,
      51, 19, 59, 27, 49, 17, 57, 25,
      15, 47, 7, 39, 13, 45, 5, 37,
      63, 31, 55, 23, 61, 29, 53, 21
    );

    return float(bayerMatrix[y * 8 + x]) / 64.0;
  }

  void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
    // Convert to grayscale using luminance formula
    float luminance = dot(inputColor.rgb, vec3(0.299, 0.587, 0.114));

    // Get screen coordinates for dithering pattern
    vec2 screenCoord = uv * resolution;
    float bayerValue = getBayerValue(screenCoord);

    // Apply dithering threshold
    float dithered = step(bayerValue, luminance * intensity);

    // Output black or white based on threshold
    outputColor = vec4(vec3(dithered), inputColor.a);
  }
`;

export class DitheringEffectImpl extends Effect {
  constructor({
    intensity = 1.0,
    blendFunction = BlendFunction.NORMAL,
  }: {
    intensity?: number;
    blendFunction?: BlendFunction;
  } = {}) {
    super("DitheringEffect", ditheringFragmentShader, {
      blendFunction,
      uniforms: new Map<string, Uniform>([
        ["intensity", new Uniform(intensity)],
      ]),
    });
  }

  get intensity(): number {
    return this.uniforms.get("intensity")!.value as number;
  }

  set intensity(value: number) {
    this.uniforms.get("intensity")!.value = value;
  }
}

export interface DitheringPassProps {
  intensity?: number;
  blendFunction?: BlendFunction;
}

export const DitheringPass = forwardRef<DitheringEffectImpl, DitheringPassProps>(
  function DitheringPass({ intensity = 1.0, blendFunction = BlendFunction.NORMAL }, ref) {
    const effect = useMemo(
      () => new DitheringEffectImpl({ intensity, blendFunction }),
      [intensity, blendFunction]
    );

    // eslint-disable-next-line react/no-unknown-property
    return <primitive ref={ref} object={effect} />;
  }
);

"use client";

import { Effect, BlendFunction } from "postprocessing";
import { Uniform, Vector2, WebGLRenderTarget, WebGLRenderer } from "three";
import { forwardRef, useMemo } from "react";
import orderedDitheringShader from "./OrderedDitheringShader";

export interface OrderedDitheringEffectOptions {
  time?: number;
  resolution?: Vector2;
  gridSize?: number;
  luminanceMethod?: number;
  invertColor?: boolean;
  pixelSizeRatio?: number;
  grayscaleOnly?: boolean;
  blendFunction?: BlendFunction;
}

export class OrderedDitheringEffectImpl extends Effect {
  constructor({
    time = 0,
    resolution = new Vector2(1, 1),
    gridSize = 4.0,
    luminanceMethod = 0,
    invertColor = false,
    pixelSizeRatio = 1,
    grayscaleOnly = false,
    blendFunction = BlendFunction.NORMAL,
  }: OrderedDitheringEffectOptions = {}) {
    const uniforms = new Map<string, Uniform>([
      ["time", new Uniform(time)],
      ["resolution", new Uniform(resolution)],
      ["gridSize", new Uniform(gridSize)],
      ["luminanceMethod", new Uniform(luminanceMethod)],
      ["invertColor", new Uniform(invertColor ? 1 : 0)],
      ["ditheringEnabled", new Uniform(1)],
      ["pixelSizeRatio", new Uniform(pixelSizeRatio)],
      ["grayscaleOnly", new Uniform(grayscaleOnly ? 1 : 0)],
    ]);

    super("OrderedDitheringEffect", orderedDitheringShader, {
      blendFunction,
      uniforms,
    });
  }

  override update(
    _renderer: WebGLRenderer,
    inputBuffer: WebGLRenderTarget,
    deltaTime: number
  ): void {
    const timeUniform = this.uniforms.get("time");
    if (timeUniform && typeof timeUniform.value === "number") {
      timeUniform.value += deltaTime;
    }

    const resolutionUniform = this.uniforms.get("resolution");
    if (resolutionUniform?.value instanceof Vector2) {
      resolutionUniform.value.set(inputBuffer.width, inputBuffer.height);
    }
  }

  setGridSize(size: number) {
    const gridSizeUniform = this.uniforms.get("gridSize");
    if (gridSizeUniform) {
      gridSizeUniform.value = size;
    }
  }

  setPixelSizeRatio(ratio: number) {
    const pixelSizeRatioUniform = this.uniforms.get("pixelSizeRatio");
    if (pixelSizeRatioUniform) {
      pixelSizeRatioUniform.value = ratio;
    }
  }

  setGrayscaleOnly(grayscaleOnly: boolean) {
    const grayscaleOnlyUniform = this.uniforms.get("grayscaleOnly");
    if (grayscaleOnlyUniform) {
      grayscaleOnlyUniform.value = grayscaleOnly ? 1 : 0;
    }
  }

  setInvertColor(invertColor: boolean) {
    const invertColorUniform = this.uniforms.get("invertColor");
    if (invertColorUniform) {
      invertColorUniform.value = invertColor ? 1 : 0;
    }
  }

  setLuminanceMethod(luminanceMethod: number) {
    const luminanceMethodUniform = this.uniforms.get("luminanceMethod");
    if (luminanceMethodUniform) {
      luminanceMethodUniform.value = luminanceMethod;
    }
  }
}

export interface OrderedDitheringPassProps {
  gridSize?: number;
  luminanceMethod?: number;
  invertColor?: boolean;
  pixelSizeRatio?: number;
  grayscaleOnly?: boolean;
  blendFunction?: BlendFunction;
}

export const OrderedDitheringPass = forwardRef<
  OrderedDitheringEffectImpl,
  OrderedDitheringPassProps
>(function OrderedDitheringPass(
  {
    gridSize = 4.0,
    luminanceMethod = 0,
    invertColor = false,
    pixelSizeRatio = 1,
    grayscaleOnly = false,
    blendFunction = BlendFunction.NORMAL,
  },
  ref
) {
  const effect = useMemo(
    () =>
      new OrderedDitheringEffectImpl({
        gridSize,
        luminanceMethod,
        invertColor,
        pixelSizeRatio,
        grayscaleOnly,
        blendFunction,
      }),
    [gridSize, luminanceMethod, invertColor, pixelSizeRatio, grayscaleOnly, blendFunction]
  );

  // eslint-disable-next-line react/no-unknown-property
  return <primitive ref={ref} object={effect} />;
});

"use client";

import { Effect, BlendFunction } from "postprocessing";
import { Uniform } from "three";
import { forwardRef, useMemo } from "react";

const pixelationFragmentShader = `
  uniform float pixelSize;

  void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
    vec2 screenCoord = uv * resolution;
    vec2 pixelCoord = floor(screenCoord / pixelSize) * pixelSize + vec2(0.5);
    vec2 pixelUv = pixelCoord / resolution;

    vec4 color = texture2D(inputBuffer, pixelUv);
    outputColor = color;
  }
`;

export class PixelationEffectImpl extends Effect {
  constructor({
    pixelSize = 6.0,
    blendFunction = BlendFunction.NORMAL,
  }: {
    pixelSize?: number;
    blendFunction?: BlendFunction;
  } = {}) {
    super("PixelationEffect", pixelationFragmentShader, {
      blendFunction,
      uniforms: new Map<string, Uniform>([
        ["pixelSize", new Uniform(pixelSize)],
      ]),
    });
  }

  get pixelSize(): number {
    return this.uniforms.get("pixelSize")!.value as number;
  }

  set pixelSize(value: number) {
    this.uniforms.get("pixelSize")!.value = value;
  }
}

export interface PixelationPassProps {
  pixelSize?: number;
  blendFunction?: BlendFunction;
}

export const PixelationPass = forwardRef<PixelationEffectImpl, PixelationPassProps>(
  function PixelationPass({ pixelSize = 6.0, blendFunction = BlendFunction.NORMAL }, ref) {
    const effect = useMemo(
      () => new PixelationEffectImpl({ pixelSize, blendFunction }),
      [pixelSize, blendFunction]
    );

    // eslint-disable-next-line react/no-unknown-property
    return <primitive ref={ref} object={effect} />;
  }
);

import "server-only";

import {
  isRetryableError,
  getRetryDelay,
  externalServiceError,
  timeoutError,
  wrapError,
} from "@/shared/errors/app-error";
import { logSystemEvent } from "@/shared/lib/observability/system-logger";

/**
 * Configuration for retry behavior.
 */
export type RetryOptions = {
  /** Maximum number of retry attempts (default: 3) */
  maxAttempts?: number;
  /** Initial delay in milliseconds before first retry (default: 1000) */
  initialDelayMs?: number;
  /** Maximum delay in milliseconds between retries (default: 30000) */
  maxDelayMs?: number;
  /** Multiplier for exponential backoff (default: 2) */
  backoffMultiplier?: number;
  /** Whether to add jitter to delay (default: true) */
  jitter?: boolean;
  /** Timeout for each attempt in milliseconds (optional) */
  timeoutMs?: number;
  /** Custom function to determine if error is retryable */
  isRetryable?: (error: unknown) => boolean;
  /** Callback on each retry attempt */
  onRetry?: (attempt: number, error: unknown, nextDelayMs: number) => void;
  /** Source identifier for logging */
  source?: string;
  /** Whether to log retry attempts */
  logRetries?: boolean;
};

const DEFAULT_OPTIONS: Required<Omit<RetryOptions, "timeoutMs" | "onRetry" | "isRetryable" | "source">> = {
  maxAttempts: 3,
  initialDelayMs: 1000,
  maxDelayMs: 30000,
  backoffMultiplier: 2,
  jitter: true,
  logRetries: true,
};

/**
 * Calculates delay for next retry with exponential backoff and optional jitter.
 */
function calculateDelay(
  attempt: number,
  options: Required<Omit<RetryOptions, "timeoutMs" | "onRetry" | "isRetryable" | "source">>
): number {
  const exponentialDelay =
    options.initialDelayMs * Math.pow(options.backoffMultiplier, attempt - 1);
  const cappedDelay = Math.min(exponentialDelay, options.maxDelayMs);

  if (options.jitter) {
    // Add random jitter of ±25%
    const jitterFactor = 0.75 + Math.random() * 0.5;
    return Math.round(cappedDelay * jitterFactor);
  }

  return cappedDelay;
}

/**
 * Wraps a promise with a timeout.
 */
function withTimeout<T>(
  promise: Promise<T>,
  timeoutMs: number,
  operation: string
): Promise<T> {
  return new Promise<T>((resolve: (value: T | PromiseLike<T>) => void, reject: (reason?: any) => void) => {
    const timer = setTimeout(() => {
      reject(timeoutError(`Operation timed out after ${timeoutMs}ms`, { operation }));
    }, timeoutMs);

    promise
      .then((result: T) => {
        clearTimeout(timer);
        resolve(result);
      })
      .catch((error: unknown) => {
        clearTimeout(timer);
        reject(wrapError(error));
      });
  });
}

/**
 * Delays execution for a specified time.
 */
function delay(ms: number): Promise<void> {
  return new Promise<void>((resolve: (value: void | PromiseLike<void>) => void) => setTimeout(resolve, ms));
}

/**
 * Executes an async operation with automatic retries on failure.
 *
 * Features:
 * - Exponential backoff with jitter
 * - Configurable retry conditions
 * - Optional timeout per attempt
 * - Logging of retry attempts
 *
 * @example
 * ```ts
 * const result = await withRetry(
 *   () => fetchExternalApi(),
 *   {
 *     maxAttempts: 3,
 *     source: "external-api",
 *     timeoutMs: 5000,
 *   }
 * );
 * ```
 */
export async function withRetry<T>(
  operation: () => Promise<T>,
  options?: RetryOptions
): Promise<T> {
  const opts = { ...DEFAULT_OPTIONS, ...options };
  const { maxAttempts, timeoutMs, isRetryable, onRetry, source, logRetries } = {
    ...opts,
    timeoutMs: options?.timeoutMs,
    isRetryable: options?.isRetryable,
    onRetry: options?.onRetry,
    source: options?.source,
    logRetries: opts.logRetries,
  };

  let lastError: unknown;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      // Execute with optional timeout
      const result = timeoutMs
        ? await withTimeout(operation(), timeoutMs, source ?? "operation")
        : await operation();

      return result;
    } catch (error) {
      lastError = error;

      // Check if we should retry
      const shouldRetry =
        attempt < maxAttempts &&
        (isRetryable?.(error) ?? isRetryableError(error) ?? true);

      if (!shouldRetry) {
        throw error;
      }

      // Calculate delay
      const errorDelay = getRetryDelay(error);
      const nextDelay = errorDelay ?? calculateDelay(attempt, opts);

      // Log retry attempt
      if (logRetries) {
        void logSystemEvent({
          level: "warn",
          message: `Retry attempt ${attempt}/${maxAttempts} after ${nextDelay}ms`,
          source: source ?? "retry",
          error,
          context: {
            attempt,
            maxAttempts,
            delayMs: nextDelay,
          },
        });
      }

      // Call retry callback
      onRetry?.(attempt, error, nextDelay);

      // Wait before next attempt
      await delay(nextDelay);
    }
  }

  // All attempts failed
  throw lastError;
}

/**
 * Executes multiple operations in parallel with retry support.
 * Returns results for successful operations and errors for failed ones.
 */
export async function withRetryAll<T>(
  operations: Array<() => Promise<T>>,
  options?: RetryOptions
): Promise<Array<{ success: true; result: T } | { success: false; error: unknown }>> {
  return Promise.all(
    operations.map(async (op: () => Promise<T>) => {
      try {
        const result = await withRetry(op, options);
        return { success: true as const, result };
      } catch (error) {
        return { success: false as const, error };
      }
    })
  );
}

/**
 * Circuit breaker state for a service.
 */
type CircuitState = {
  failures: number;
  lastFailure: number;
  isOpen: boolean;
};

const circuitStates = new Map<string, CircuitState>();

/**
 * Configuration for circuit breaker.
 */
export type CircuitBreakerOptions = {
  /** Number of failures before opening circuit (default: 5) */
  failureThreshold?: number;
  /** Time in ms before attempting to close circuit (default: 60000) */
  resetTimeoutMs?: number;
  /** Identifier for this circuit */
  circuitId: string;
};

const DEFAULT_CIRCUIT_OPTIONS = {
  failureThreshold: 5,
  resetTimeoutMs: 60000,
};

/**
 * Executes an operation with circuit breaker pattern.
 * Prevents cascade failures by temporarily blocking calls to failing services.
 *
 * @example
 * ```ts
 * const result = await withCircuitBreaker(
 *   () => callExternalService(),
 *   { circuitId: "external-service" }
 * );
 * ```
 */
export async function withCircuitBreaker<T>(
  operation: () => Promise<T>,
  options: CircuitBreakerOptions
): Promise<T> {
  const opts = { ...DEFAULT_CIRCUIT_OPTIONS, ...options };
  const { circuitId, failureThreshold, resetTimeoutMs } = opts;

  // Get or initialize circuit state
  let state = circuitStates.get(circuitId);
  if (!state) {
    state = { failures: 0, lastFailure: 0, isOpen: false };
    circuitStates.set(circuitId, state);
  }

  // Check if circuit is open
  if (state.isOpen) {
    const timeSinceLastFailure = Date.now() - state.lastFailure;
    if (timeSinceLastFailure < resetTimeoutMs) {
      throw externalServiceError(
        `Circuit breaker open for ${circuitId}`,
        { circuitId, resetInMs: resetTimeoutMs - timeSinceLastFailure },
        { retryable: true, retryAfterMs: resetTimeoutMs - timeSinceLastFailure }
      );
    }
    // Attempt to close circuit (half-open state)
    state.isOpen = false;
  }

  try {
    const result = await operation();

    // Success - reset failures
    state.failures = 0;
    return result;
  } catch (error) {
    // Record failure
    state.failures++;
    state.lastFailure = Date.now();

    // Check if threshold reached
    if (state.failures >= failureThreshold) {
      state.isOpen = true;
      void logSystemEvent({
        level: "error",
        message: `Circuit breaker opened for ${circuitId} after ${state.failures} failures`,
        source: "circuit-breaker",
        context: {
          circuitId,
          failures: state.failures,
          resetTimeoutMs,
        },
      });
    }

    throw error;
  }
}

/**
 * Resets a circuit breaker to closed state.
 */
export function resetCircuitBreaker(circuitId: string): void {
  circuitStates.delete(circuitId);
}

/**
 * Gets the current state of a circuit breaker.
 */
export function getCircuitBreakerState(
  circuitId: string
): CircuitState | undefined {
  return circuitStates.get(circuitId);
}
